use std::io::{BufRead, BufReader, Cursor};

fn collect_lines(reader: &mut BufReader<Cursor<Vec<u8>>>) -> Vec<String> {
    reader.lines().map(|l| l.unwrap()).collect()
    // Note: after draining, reader is at EOF; in practice callers seek or rebuild
